pub fn load(head: Head, payload: &[u8]) -> Result<WindowUpdate, Error> {
    debug_assert_eq!(head.kind(), crate::frame::Kind::WindowUpdate);
    if payload.len() != 4 {
        return Err(Error::BadFrameSize);
    }

    // Clear the most significant bit, as that is reserved and MUST be ignored
    // when received.
    let size_increment = unpack_octets_4!(payload, 0, u32) & !SIZE_INCREMENT_MASK;

    if size_increment == 0 {
        return Err(Error::InvalidWindowUpdateValue);
    }

    Ok(WindowUpdate {
        stream_id: head.stream_id(),
        size_increment,
    })
}

fn decode(value: &HeaderValue) -> Option<Self> {
    debug_assert!(
        value.as_bytes()[..Self::SCHEME.len()].eq_ignore_ascii_case(Self::SCHEME.as_bytes()),
        "HeaderValue to decode should start with \"Basic ..\", received = {:?}",
        value,
    );

    let bytes = value.as_bytes().get("Basic ".len()..)?;
    let non_space_pos = bytes.iter().position(|b| *b != b' ')?;
    let bytes = &bytes[non_space_pos..];

    let bytes = ENGINE.decode(bytes).ok()?;

    let decoded = String::from_utf8(bytes).ok()?;

    let colon_pos = decoded.find(':')?;

    Some(Basic { decoded, colon_pos })
}

async fn trailers() {
    let mut trailers = HeaderMap::new();
    trailers.insert("this", "a trailer".try_into().unwrap());
    let bufs = [
        Frame::data(&b"hello"[..]),
        Frame::data(&b"world!"[..]),
        Frame::trailers(trailers.clone()),
    ];

    let body = StreamBody::new(stream::iter(bufs.map(Ok::<_, Infallible>)));

    let buffered = body.collect().await.unwrap();

    assert_eq!(&trailers, buffered.trailers().unwrap());

    let mut buf = buffered.to_bytes();

    assert_eq!(&buf.copy_to_bytes(buf.remaining())[..], b"helloworld!");
}

