fn get(&mut self, query: &str, persistent: bool) -> Result<&mut VirtualStatement, Error> {
    if !persistent || !self.cached.is_enabled() {
        return Ok(self.temp.insert(VirtualStatement::new(query, false)?));
    }

    let exists = self.cached.contains_key(query);

    if !exists {
        let statement = VirtualStatement::new(query, true)?;
        self.cached.insert(query, statement);
    }

    let statement = self.cached.get_mut(query).unwrap();

    if exists {
        // as this statement has been executed before, we reset before continuing
        statement.reset()?;
    }

    Ok(statement)
}

async fn get_or_prepare_statement(
    &mut self,
    sql: &str,
) -> Result<(u32, MySqlStatementMetadata), Error> {
    if let Some(statement) = self.inner.cache_statement.get_mut(sql) {
        // <MySqlStatementMetadata> is internally reference-counted
        return Ok((*statement).clone());
    }

    let (id, metadata) = self.prepare_statement(sql).await?;

    // in case of the cache being full, close the least recently used statement
    if let Some((id, _)) = self
        .inner
        .cache_statement
        .insert(sql, (id, metadata.clone()))
    {
        self.inner
            .stream
            .send_packet(StmtClose { statement: id })
            .await?;
    }

    Ok((id, metadata))
}

pub async fn r#yield(&self, val: T) {
    let replaced = self
        .value
        .lock()
        .expect("BUG: panicked while holding a lock")
        .replace(val);

    debug_assert!(
        replaced.is_none(),
        "BUG: previously yielded value not taken"
    );

    let mut yielded = false;

    // Allows the generating future to suspend its execution without changing the task priority,
    // which would happen with `tokio::task::yield_now()`.
    //
    // Note that because this has no way to schedule a wakeup, this could deadlock the task
    // if called in the wrong place.
    future::poll_fn(|_cx| {
        if !yielded {
            yielded = true;
            Poll::Pending
        } else {
            Poll::Ready(())
        }
    })
    .await
}

async fn close(mut self) -> Result<(), Error> {
    if let OptimizeOnClose::Enabled { analysis_limit } = self.optimize_on_close {
        let mut pragma_string = String::new();
        if let Some(limit) = analysis_limit {
            write!(pragma_string, "PRAGMA analysis_limit = {limit}; ").ok();
        }
        pragma_string.push_str("PRAGMA optimize;");
        self.execute(AssertSqlSafe(pragma_string)).await?;
    }
    let shutdown = self.worker.shutdown();
    // Drop the statement worker, which should
    // cover all references to the connection handle outside of the worker thread
    drop(self);
    // Ensure the worker thread has terminated
    shutdown.await
}

async fn recv_packet_part(&mut self) -> Result<Bytes, Error> {
    // https://dev.mysql.com/doc/dev/mysql-server/8.0.12/page_protocol_basic_packets.html
    // https://mariadb.com/kb/en/library/0-packet/#standard-packet

    let mut header: Bytes = self.socket.read(4).await?;

    // cannot overflow
    #[allow(clippy::cast_possible_truncation)]
    let packet_size = header.get_uint_le(3) as usize;
    let sequence_id = header.get_u8();

    self.sequence_id = sequence_id.wrapping_add(1);

    let payload: Bytes = self.socket.read(packet_size).await?;

    // TODO: packet compression

    Ok(payload)
}

async fn recv_desc_rows(conn: &mut PgConnection) -> Result<Option<RowDescription>, Error> {
    let rows: Option<RowDescription> = match conn.inner.stream.recv().await? {
        // describes the rows that will be returned when the statement is eventually executed
        message if message.format == BackendMessageFormat::RowDescription => {
            Some(message.decode()?)
        }

        // no data would be returned if this statement was executed
        message if message.format == BackendMessageFormat::NoData => None,

        message => {
            return Err(err_protocol!(
                "expecting RowDescription or NoData but received {:?}",
                message.format
            ));
        }
    };

    Ok(rows)
}

