fn test_parse_in_memory() -> Result<(), Error> {
    let options: SqliteConnectOptions = "sqlite::memory:".parse()?;
    assert!(options.in_memory);
    assert!(options.shared_cache);

    let options: SqliteConnectOptions = "sqlite://?mode=memory".parse()?;
    assert!(options.in_memory);
    assert!(options.shared_cache);

    let options: SqliteConnectOptions = "sqlite://:memory:".parse()?;
    assert!(options.in_memory);
    assert!(options.shared_cache);

    let options: SqliteConnectOptions = "sqlite://?mode=memory&cache=private".parse()?;
    assert!(options.in_memory);
    assert!(!options.shared_cache);

    Ok(())
}

fn retain(&mut self, mut f: impl FnMut(&Todo) -> bool) {
    self.0.retain(|todo| {
        let retain = f(todo);
        // because these signals are created at the top level,
        // they are owned by the <TodoMVC/> component and not
        // by the individual <Todo/> components. This means
        // that if they are not manually disposed when removed, they
        // will be held onto until the <TodoMVC/> is unmounted.
        if !retain {
            todo.title.dispose();
            todo.completed.dispose();
        }
        retain
    })
}

pub fn new() -> DuplexEventsPlugin {
    // For sending messages from bevy to the client
    let (bevy_sender, client_receiver) = crossbeam_channel::bounded(50);
    // For sending message from the client to bevy
    let (client_sender, bevy_receiver) = crossbeam_channel::bounded(50);
    DuplexEventsPlugin {
        client_processor: EventProcessor {
            sender: client_sender,
            receiver: client_receiver,
        },
        plugin_processor: EventProcessor {
            sender: bevy_sender,
            receiver: bevy_receiver,
        },
    }
}

fn track_field(&self) {
    let mut full_path = self.path().into_iter().collect::<StorePath>();
    let trigger = self.get_trigger(self.path().into_iter().collect());
    trigger.this.track();
    trigger.children.track();

    // tracks `this` for all ancestors: i.e., it will track any change that is made
    // directly to one of its ancestors, but not a change made to a *child* of an ancestor
    // (which would end up with every subfield tracking its own siblings, because they are
    // children of its parent)
    while !full_path.is_empty() {
        full_path.pop();
        let inner = self.get_trigger(full_path.clone());
        inner.this.track();
    }
}

fn to_html_with_buf(
    self,
    buf: &mut String,
    position: &mut Position,
    escape: bool,
    mark_branches: bool,
    extra_attrs: Vec<AnyAttribute>,
) {
    if self.show_b {
        self.b
            .expect("rendering B to HTML without filling it")
            .to_html_with_buf(
                buf,
                position,
                escape,
                mark_branches,
                extra_attrs,
            );
    } else {
        self.a
            .expect("rendering A to HTML without filling it")
            .to_html_with_buf(
                buf,
                position,
                escape,
                mark_branches,
                extra_attrs,
            );
    }
}

fn mount(
    &mut self,
    _parent: &leptos::tachys::renderer::types::Element,
    _marker: Option<&leptos::tachys::renderer::types::Node>,
) {
    // TitleView::el() guarantees that there is a <title> in the <head>
    // so there is no element to be mounted
    //
    // "mounting" in this case means that we actually want this title to be in active use
    // as a result, we will push it into the title stack and revalidate
    self.meta.title.push_text_and_formatter(
        self.id,
        self.text.take(),
        self.formatter.take(),
    );
}

pub fn use_head() -> MetaContext {
    match use_context::<MetaContext>() {
        None => {
            debug_warn!(
                "use_head() is being called without a MetaContext being \
                 provided. We'll automatically create and provide one, but if \
                 this is being called in a child route it may cause bugs. To \
                 be safe, you should provide_meta_context() somewhere in the \
                 root of the app."
            );
            let meta = MetaContext::new();
            provide_context(meta.clone());
            meta
        }
        Some(ctx) => ctx,
    }
}

pub fn hydrate_islands() {
    use hydration_context::{HydrateSharedContext, SharedContext};
    use std::sync::Arc;

    // use wasm-bindgen-futures to drive the reactive system
    // we ignore the return value because an Err here just means the wasm-bindgen executor is
    // already initialized, which is not an issue
    _ = Executor::init_wasm_bindgen();

    #[cfg(debug_assertions)]
    FIRST_CALL.set(false);

    // create a new reactive owner and use it as the root node to run the app
    let sc = HydrateSharedContext::new();
    sc.set_is_hydrating(false); // islands mode starts in "not hydrating"
    let owner = Owner::new_root(Some(Arc::new(sc)));
    owner.set();
    std::mem::forget(owner);
}

pub fn setup(&mut self) {
    if self.is_setup {
        return;
    };
    App::new()
        .add_plugins(DefaultPlugins.set(WindowPlugin {
            primary_window: Some(Window {
                canvas: Some(self.canvas_id.clone()),
                ..default()
            }),
            ..default()
        }))
        .add_plugins(self.evt_plugin.clone())
        .insert_resource(SharedResource(self.shared_state.clone()))
        .add_systems(Startup, setup_scene)
        .add_systems(Update, handle_bevy_event)
        .run();
    self.is_setup = true;
}

pub async fn file_and_error_handler(
    uri: Uri,
    State(options): State<LeptosOptions>,
    req: Request<Body>,
) -> AxumResponse {
    let root = options.site_root.clone();
    let res = get_static_file(uri.clone(), &root).await.unwrap();

    if res.status() == StatusCode::OK {
        res.into_response()
    } else {
        leptos::logging::log!("{:?}:{}", res.status(), uri);
        let handler =
            leptos_axum::render_app_to_stream(options.to_owned(), || {
                error_template(RwSignal::new(leptos::Errors::default()))
            });
        handler(req).await.into_response()
    }
}

fn test_redirect_policy_limit() {
    let policy = Policy::default();
    let next = Url::parse("http://x.y/z").unwrap();
    let mut previous = (0..=9)
        .map(|i| Url::parse(&format!("http://a.b/c/{i}")).unwrap())
        .collect::<Vec<_>>();

    match policy.check(StatusCode::FOUND, &next, &previous) {
        ActionKind::Follow => (),
        other => panic!("unexpected {other:?}"),
    }

    previous.push(Url::parse("http://a.b.d/e/33").unwrap());

    match policy.check(StatusCode::FOUND, &next, &previous) {
        ActionKind::Error(err) if err.is::<TooManyRedirects>() => (),
        other => panic!("unexpected {other:?}"),
    }
}

pub fn schema(
    database: DatabaseConnection,
    depth: Option<usize>,
    complexity: Option<usize>,
) -> Result<Schema, SchemaError> {
    // Construct GraphQL schema
    let builder = Builder::new(&CONTEXT, database.clone());
    // Register SeaORM Entities
    let builder = crate::models::_entities::register_entity_modules(builder);
    builder
        // Maximum depth of the constructed query
        .set_depth_limit(depth)
        // Maximum complexity of the constructed query
        .set_complexity_limit(complexity)
        .schema_builder()
        // GraphQL schema with database connection
        .data(database)
        .finish()
}

pub fn schema(
    database: DatabaseConnection,
    depth: usize,
    complexity: usize,
) -> Result<Schema, SchemaError> {
    // Builder of Seaography query root
    let builder = Builder::new(&CONTEXT, database.clone());
    // Register SeaORM entities
    let builder = crate::models::_entities::register_entity_modules(builder);
    // Configure async GraphQL limits
    let schema = builder
        .schema_builder()
        // The depth is the number of nesting levels of the field
        .limit_depth(depth)
        // The complexity is the number of fields in the query
        .limit_complexity(complexity);
    // Finish up with including SeaORM database connection
    schema.data(database).finish()
}

async fn ws_handler(
    ws: WebSocketUpgrade,
    user_agent: Option<TypedHeader<headers::UserAgent>>,
    ConnectInfo(addr): ConnectInfo<SocketAddr>,
) -> impl IntoResponse {
    let user_agent = if let Some(TypedHeader(user_agent)) = user_agent {
        user_agent.to_string()
    } else {
        String::from("Unknown browser")
    };
    println!("`{user_agent}` at {addr} connected.");
    // finalize the upgrade process by returning upgrade callback.
    // we can customize the callback by sending additional info such as address.
    ws.on_upgrade(move |socket| handle_socket(socket, addr))
}

async fn main() {
    // build our application with a route
    let app = Router::new().route("/", get(handler));

    let mut listenfd = ListenFd::from_env();
    let listener = match listenfd.take_tcp_listener(0).unwrap() {
        // if we are given a tcp listener on listen fd 0, we use that one
        Some(listener) => {
            listener.set_nonblocking(true).unwrap();
            TcpListener::from_std(listener).unwrap()
        }
        // otherwise fall back to local listening
        None => TcpListener::bind("127.0.0.1:3000").await.unwrap(),
    };

    // run it
    println!("listening on {}", listener.local_addr().unwrap());
    axum::serve(listener, app).await;
}

